  width: number;
  height: number;
  tick: number;
  isRunning: boolean;
}

// Simple pseudo-random number generator
export const randomRange = (min: number, max: number) => Math.random() * (max - min) + min;
export const randomInt = (min: number, max: number) => Math.floor(randomRange(min, max));

export const getRandomColor = () => {
  const letters = '0123456789ABCDEF';
  let color = '#';
  for (let i = 0; i < 6; i++) {
    color += letters[Math.floor(Math.random() * 16)];
  }
  return color;
};

// Simplified 2D Noise (Value Noise)
export class SimpleNoise {
  size: number;
  values: number[];

  constructor(size: number = 256) {
    this.size = size;
    this.values = new Array(size * size).fill(0).map(() => Math.random());
  }

  get(x: number, y: number): number {
    const X = Math.floor(x) & (this.size - 1);
    const Y = Math.floor(y) & (this.size - 1);
    return this.values[X + Y * this.size];
  }

  // Bilinear interpolation noise
  noise(x: number, y: number): number {
    const xf = Math.floor(x);
    const yf = Math.floor(y);
    const u = x - xf;
    const v = y - yf;

    // Smoothstep
    const su = u * u * (3 - 2 * u);
    const sv = v * v * (3 - 2 * v);

    const aa = this.get(xf, yf);
    const ab = this.get(xf, yf + 1);
    const ba = this.get(xf + 1, yf);
    const bb = this.get(xf + 1, yf + 1);

    const lerp1 = aa + su * (ba - aa);
    const lerp2 = ab + su * (bb - ab);

    return lerp1 + sv * (lerp2 - lerp1);
  }

  // Fractal Brownian Motion
  fbm(x: number, y: number, octaves: number = 4): number {
    let value = 0;
    let amplitude = 0.5;
    let frequency = 1;

    for (let i = 0; i < octaves; i++) {
      value += this.noise(x * frequency, y * frequency) * amplitude;
      amplitude *= 0.5;
      frequency *= 2;
    }
    return value;
  }
}

import { Cell, TerrainType } from '../types';
import { SimpleNoise } from '../utils/random';

const WIDTH = 150;
const HEIGHT = 100;

const createEmptyGrid = (width: number, height: number, defaultTerrain: TerrainType): Cell[] => {
  const cells: Cell[] = [];
  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      cells.push({
        x,
        y,
        terrain: defaultTerrain,
        ownerId: null,
        cityId: null,
        defense: 0,
      });
    }
  }
  return cells;
};

export const generateWorld = (): Cell[] => {
  const cells = createEmptyGrid(WIDTH, HEIGHT, TerrainType.Water);
  const noise = new SimpleNoise(256);
  const scale = 0.05;

  for (let i = 0; i < cells.length; i++) {
    const c = cells[i];
    const value = noise.fbm(c.x * scale, c.y * scale, 5);

    if (value > 0.65) {
      c.terrain = TerrainType.Mountain;
    } else if (value > 0.45) {
      c.terrain = TerrainType.Land;
    } else {
      c.terrain = TerrainType.Water;
    }
  }
  return cells;
};

export const generateContinents = (): Cell[] => {
  const cells = createEmptyGrid(WIDTH, HEIGHT, TerrainType.Water);
  const numContinents = 5;
  const noise = new SimpleNoise(256);

  // Center points for continents
  const centers = [];
  for(let i=0; i<numContinents; i++) {
    centers.push({
        x: Math.random() * WIDTH,
        y: Math.random() * HEIGHT
    });
  }

  for (let i = 0; i < cells.length; i++) {
    const c = cells[i];
    let maxInfluence = 0;

    // Metaball-ish approach combined with noise
    for(const center of centers) {
        const dx = c.x - center.x;
        const dy = c.y - center.y;
        const dist = Math.sqrt(dx*dx + dy*dy);
        const influence = (20 / (dist + 1)); 
        maxInfluence += influence;
    }

    const noiseVal = noise.fbm(c.x * 0.1, c.y * 0.1, 2) * 2;

    if (maxInfluence + noiseVal > 3.0) {
       c.terrain = TerrainType.Land;
       if (maxInfluence + noiseVal > 4.5) {
           c.terrain = TerrainType.Mountain;
       }
    }
  }

  return cells;
};

export const generateCustom = (): Cell[] => {
  return createEmptyGrid(WIDTH, HEIGHT, TerrainType.Water);
};

export const MAP_WIDTH = WIDTH;
export const MAP_HEIGHT = HEIGHT;

import { Cell, Country, City, TerrainType } from '../types';
import { MAP_WIDTH, MAP_HEIGHT } from './MapGenerators';
import { getRandomColor } from '../utils/random';

export class SimulationEngine {
  cells: Cell[];
  countries: Country[];
  cities: City[];
  width: number;
  height: number;

  // Game Logic state
  allianceTracker: Map<string, number> = new Map(); // Key "id1-id2", Val: ticks of peace

  constructor(cells: Cell[], width: number, height: number) {
    this.cells = cells;
    this.width = width;
    this.height = height;
    this.countries = [];
    this.cities = [];
  }

  // --- Helpers ---
  getIndex(x: number, y: number): number {
    if (x < 0 || x >= this.width || y < 0 || y >= this.height) return -1;
    return y * this.width + x;
  }

  getNeighbors(index: number): number[] {
    const x = index % this.width;
    const y = Math.floor(index / this.width);
    const neighbors = [];

    const dirs = [[0,1], [0,-1], [1,0], [-1,0]];
    for(const [dx, dy] of dirs) {
      const idx = this.getIndex(x + dx, y + dy);
      if (idx !== -1) neighbors.push(idx);
    }
    return neighbors;
  }

  // --- Actions ---

  spawnCountry(x: number, y: number): void {
    const idx = this.getIndex(x, y);
    if (idx === -1) return;

    const cell = this.cells[idx];
    if (cell.terrain === TerrainType.Water) return;

    // Check if already owned
    if (cell.ownerId !== null) return;

    const newId = this.countries.length + 1;
    const color = getRandomColor();

    const newCountry: Country = {
      id: newId,
      name: `Nation ${newId}`,
      color: color,
      score: 1,
      money: 0,
      capitalId: idx,
    };

    this.countries.push(newCountry);
    cell.ownerId = newId;
    cell.defense = 100; // Strong start
  }

  placeCity(x: number, y: number): void {
     const idx = this.getIndex(x, y);
     if (idx === -1) return;
     const cell = this.cells[idx];
     if (cell.terrain === TerrainType.Water) return;

     // Prevent duplicates
     if (cell.cityId !== null) return;

     const cityId = this.cities.length + 1;
     this.cities.push({
         id: cityId,
         name: `City ${cityId}`,
         cellIndex: idx,
         ownerId: cell.ownerId
     });
     cell.cityId = cityId;
     cell.defense += 50; // Bonus defense
  }

  paintTerrain(x: number, y: number, type: TerrainType): void {
      const idx = this.getIndex(x, y);
      if (idx !== -1) {
          this.cells[idx].terrain = type;
          // Reset ownership if turning to water
          if (type === TerrainType.Water) {
              this.cells[idx].ownerId = null;
              this.cells[idx].cityId = null;
              this.cells[idx].defense = 0;
          }
      }
  }

  // --- Tick Logic ---

  tick(): void {
    // We shuffle a list of indices to process to avoid directional bias
    // Optimization: Only process border cells? For now, brute force is fine for 15k cells.
    // Optimization 2: Random sampling. We don't need to update EVERY cell every tick.
    // Let's update 10% of the map per tick for performance and "organic" feel.

    const numUpdates = Math.floor(this.cells.length * 0.2); 

    for (let i = 0; i < numUpdates; i++) {
        const idx = Math.floor(Math.random() * this.cells.length);
        this.processCell(idx);
    }

    // Occasional Global Checks (Revolts, Alliances)
    if (Math.random() < 0.01) {
        this.checkRevolts();
    }

    this.updateScores();
  }

  processCell(idx: number) {
      const cell = this.cells[idx];

      // Only owned land acts
      if (cell.ownerId === null || cell.terrain === TerrainType.Water) return;

      const neighbors = this.getNeighbors(idx);
      const neighborIdx = neighbors[Math.floor(Math.random() * neighbors.length)];
      const target = this.cells[neighborIdx];

      // Interaction Logic
      if (target.terrain === TerrainType.Water) return;

      // 1. Expansion (Claim Empty Land)
      if (target.ownerId === null) {
          // Mountains are harder to claim
          const difficulty = target.terrain === TerrainType.Mountain ? 0.1 : 0.8;
          if (Math.random() < difficulty) {
              target.ownerId = cell.ownerId;
              target.defense = 10;
          }
          return;
      }

      // 2. War (Attack Enemy)
      if (target.ownerId !== cell.ownerId) {
          // Check Alliance (Simplified: 5% chance to ignore war if not forced)
          // Real alliance logic would check the alliance map.

          // Attack calculation
          // Attacker strength: Random + Defense support
          // Defender strength: Random + Defense

          const attackRoll = Math.random() * (cell.defense + 50);
          const defenseRoll = Math.random() * (target.defense + (target.cityId ? 50 : 0) + (target.terrain === TerrainType.Mountain ? 30 : 0));

          if (attackRoll > defenseRoll) {
              // Successful invasion
              target.defense -= 20;
              if (target.defense <= 0) {
                  target.ownerId = cell.ownerId;
                  target.defense = 20; // Reset defense for new owner

                  // Capture City Bonus
                  if (target.cityId) {
                      // Boost all cells of this country? Or just local?
                      cell.defense += 50; 
                  }
              }
          } else {
              // Failed attack, defender hardens
              target.defense = Math.min(target.defense + 5, 100);
          }
      } else {
          // 3. Reinforce (Heal own land)
          if (target.defense < 100) {
              target.defense += 1;
          }
      }
  }

  updateScores() {
      // Reset scores
      const scores = new Map<number, number>();
      for(const c of this.countries) scores.set(c.id, 0);

      for(const cell of this.cells) {
          if (cell.ownerId) {
              const current = scores.get(cell.ownerId) || 0;
              scores.set(cell.ownerId, current + 1);
          }
      }

      for(const c of this.countries) {
          c.score = scores.get(c.id) || 0;
      }

      // Remove dead countries
      // this.countries = this.countries.filter(c => c.score > 0);
  }

  checkRevolts() {
    // Very expensive, run rarely.
    // BFS from Capital to see if territory is contiguous.
    // If not, split off.

    // Simplified: Just check if a random country is fragmented.
    if (this.countries.length === 0) return;
    const country = this.countries[Math.floor(Math.random() * this.countries.length)];
    if (country.score < 10) return; // Too small to revolt
    if (!country.capitalId) return;

    // BFS
    const queue = [country.capitalId];
    const visited = new Set<number>();
    visited.add(country.capitalId);

    // Safety break
    let limit = 0;
    while(queue.length > 0 && limit < 5000) {
        limit++;
        const curr = queue.shift()!;
        const neighbors = this.getNeighbors(curr);
        for(const n of neighbors) {
            if (this.cells[n].ownerId === country.id && !visited.has(n)) {
                visited.add(n);
                queue.push(n);
            }
        }
    }

    // If visited count < total score, we have disconnected lands
    if (visited.size < country.score * 0.8) { // If less than 80% is connected to capital
        // Create rebel faction
        const rebelId = this.countries.length + 1;
        const rebelColor = getRandomColor();
        this.countries.push({
            id: rebelId,
            name: `${country.name} Separatists`,
            color: rebelColor,
            score: 0,
            money: 0,
            isRebel: true,
            capitalId: null
        });

        // Convert unvisited cells to rebels
        for(let i=0; i<this.cells.length; i++) {
            if (this.cells[i].ownerId === country.id && !visited.has(i)) {
                this.cells[i].ownerId = rebelId;
                // Set first rebel cell as capital
                if (this.countries[this.countries.length-1].capitalId === null) {
                    this.countries[this.countries.length-1].capitalId = i;
                }
            }
        }
    }
  }
}

import React, { useRef, useEffect } from 'react';
import { SimulationEngine } from '../services/SimulationEngine';
import { TerrainType } from '../types';

interface Props {
  engine: SimulationEngine;
  onInteract: (x: number, y: number) => void;
  width: number;
  height: number;
}

export const CanvasRenderer: React.FC<Props> = ({ engine, onInteract, width, height }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Helper to convert hex to rgb
  const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
      r: parseInt(result[1], 16),
      g: parseInt(result[2], 16),
      b: parseInt(result[3], 16)
    } : { r: 0, g: 0, b: 0 };
  };

  // Cache colors to avoid parsing every frame
  const colorCache = useRef<Map<string, {r:number, g:number, b:number}>>(new Map());

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: false }); // Optimize for no alpha
    if (!ctx) return;

    let animationFrameId: number;

    const render = () => {
      const { cells, width: mapW, height: mapH, countries } = engine;

      // Create ImageData once or reuse? Recreating is safer for resizing, but reuse is faster.
      // Assuming fixed map size for now.
      const imageData = ctx.createImageData(mapW, mapH);
      const data = imageData.data;

      // Update color cache if needed
      countries.forEach(c => {
        if (!colorCache.current.has(c.color)) {
          colorCache.current.set(c.color, hexToRgb(c.color));
        }
      });

      for (let i = 0; i < cells.length; i++) {
        const cell = cells[i];
        const idx = i * 4;

        let r, g, b;

        if (cell.ownerId) {
          // Country Color
          const country = countries.find(c => c.id === cell.ownerId);
          if (country) {
            const rgb = colorCache.current.get(country.color) || {r:255, g:255, b:255};

            // darken based on defense/mountain to give texture
            const variance = cell.terrain === TerrainType.Mountain ? -40 : 0;
            const cityHighlight = cell.cityId ? 40 : 0; // Brighten cities

            r = Math.min(255, Math.max(0, rgb.r + variance + cityHighlight));
            g = Math.min(255, Math.max(0, rgb.g + variance + cityHighlight));
            b = Math.min(255, Math.max(0, rgb.b + variance + cityHighlight));
          } else {
             // Fallback
             r=255; g=255; b=255;
          }
        } else {
          // Terrain Color
          switch (cell.terrain) {
            case TerrainType.Water:
              r = 30; g = 41; b = 59; // Slate-800 ish
              break;
            case TerrainType.Land:
              r = 71; g = 85; b = 105; // Slate-600
              break;
            case TerrainType.Mountain:
              r = 148; g = 163; b = 184; // Slate-400
              break;
            default:
              r = 0; g = 0; b = 0;
          }
        }

        data[idx] = r;
        data[idx + 1] = g;
        data[idx + 2] = b;
        data[idx + 3] = 255; // Alpha
      }

      // Scale up: Draw ImageData to a small offscreen canvas or just scale via CSS?
      // CSS scaling causes blur. 
      // Better: Draw to small canvas, then drawImage with imageSmoothingEnabled = false to main canvas.

      // Actually, let's just use the main canvas as the small buffer and scale with CSS
      // ensuring pixelated rendering.
      ctx.putImageData(imageData, 0, 0);

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
    };
  }, [engine, width, height]);


  const handlePointer = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (!canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const scaleX = engine.width / rect.width;
      const scaleY = engine.height / rect.height;

      const x = Math.floor((e.clientX - rect.left) * scaleX);
      const y = Math.floor((e.clientY - rect.top) * scaleY);

      onInteract(x, y);
  };

  // Handle dragging for drawing
  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (e.buttons === 1) { // Left click held
          handlePointer(e);
      }
  };

  return (
    <div ref={containerRef} className="w-full h-full flex items-center justify-center bg-slate-950 overflow-hidden relative shadow-2xl border border-slate-800 rounded-lg">
      <canvas
        ref={canvasRef}
        width={engine.width}
        height={engine.height}
        className="w-full h-full max-w-[100%] max-h-[100%] object-contain image-pixelated cursor-crosshair"
        style={{ imageRendering: 'pixelated' }}
        onMouseDown={handlePointer}
        onMouseMove={handleMouseMove}
      />
    </div>
  );
};

import React from 'react';
import { Country } from '../types';
import { Trophy, Skull, Flag } from 'lucide-react';

interface Props {
  countries: Country[];
}

export const Leaderboard: React.FC<Props> = ({ countries }) => {
  const sorted = [...countries].sort((a, b) => b.score - a.score);

  return (
    <div className="absolute top-4 right-4 w-64 bg-slate-900/90 backdrop-blur-sm border border-slate-700 rounded-lg shadow-xl p-4 max-h-[50vh] overflow-y-auto z-20">
      <div className="flex items-center gap-2 mb-3 text-slate-200 border-b border-slate-700 pb-2">
        <Trophy className="w-4 h-4 text-yellow-500" />
        <h2 className="font-bold text-sm uppercase tracking-wider">Leaderboard</h2>
      </div>

      <div className="space-y-2">
        {sorted.length === 0 ? (
          <p className="text-xs text-slate-500 italic text-center py-4">No countries yet.</p>
        ) : (
          sorted.map((c, i) => (
            <div key={c.id} className="flex items-center justify-between text-xs group">
              <div className="flex items-center gap-2">
                 <div className="w-3 h-3 rounded-full shadow-sm ring-1 ring-white/10" style={{ backgroundColor: c.color }} />
                 <span className={`${c.score === 0 ? 'text-slate-500 line-through' : 'text-slate-300'} font-medium`}>
                    {c.name}
                 </span>
                 {c.isRebel && <Skull className="w-3 h-3 text-red-500" />}
              </div>
              <span className="font-mono text-slate-400">{c.score}</span>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MapMode, ToolType } from '../types';
import { 
  Globe, 
  Map as MapIcon, 
  Paintbrush, 
  PlusSquare, 
  Castle, 
  Trash2, 
  Play, 
  Pause,
  RefreshCw,
  Mountain
} from 'lucide-react';

interface Props {
  mapMode: MapMode;
  setMapMode: (m: MapMode) => void;
  tool: ToolType;
  setTool: (t: ToolType) => void;
  isRunning: boolean;
  toggleRun: () => void;
  onGenerate: () => void;
}

