           </button>

           <div className="h-6 w-px bg-slate-700 mx-1"></div>

           <button 
             onClick={onGenerate}
             className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-md transition-colors"
             title="Regenerate Map"
           >
             <RefreshCw className="w-5 h-5" />
           </button>
        </div>

        {/* Map Generators */}
        <div className="bg-slate-900/90 backdrop-blur-sm border border-slate-700 rounded-lg p-2 shadow-xl">
           <div className="text-[10px] uppercase text-slate-500 font-bold mb-2 px-1">Map Generator</div>
           <div className="flex flex-col gap-1">
             {mapModes.map(mode => (
               <button
                 key={mode.id}
                 onClick={() => setMapMode(mode.id)}
                 className={`flex items-center gap-2 px-3 py-2 rounded-md text-xs font-medium transition-all ${mapMode === mode.id ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'}`}
               >
                 <mode.icon className="w-4 h-4" />
                 {mode.label}
               </button>
             ))}
           </div>
        </div>
      </div>

      {/* Bottom Center: Toolbox */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-20">
        <div className="bg-slate-900/90 backdrop-blur-sm border border-slate-700 rounded-full px-4 py-2 shadow-2xl flex items-center gap-2">
           {tools.map(t => (
             <button
               key={t.id}
