import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SimulationEngine } from './services/SimulationEngine';
import { generateWorld, generateContinents, generateCustom, MAP_WIDTH, MAP_HEIGHT } from './services/MapGenerators';
import { CanvasRenderer } from './components/CanvasRenderer';
import { Interface } from './components/Interface';
import { Leaderboard } from './components/Leaderboard';
import { MapMode, ToolType, TerrainType } from './types';

// Initial Engine Setup
const createEngine = (mode: MapMode) => {
  let cells;
  switch (mode) {
    case MapMode.Continents: cells = generateContinents(); break;
    case MapMode.Custom: cells = generateCustom(); break;
    case MapMode.World: default: cells = generateWorld(); break;
  }
  return new SimulationEngine(cells, MAP_WIDTH, MAP_HEIGHT);
};

export default function App() {
  const [mapMode, setMapMode] = useState<MapMode>(MapMode.World);
  const [tool, setTool] = useState<ToolType>(ToolType.SpawnCountry);
  const [isRunning, setIsRunning] = useState(false);
  const [engine, setEngine] = useState<SimulationEngine>(() => createEngine(MapMode.World));

  // We use a "tick" state just to force React to update the Leaderboard occasionally.
  // The Canvas updates independently via requestAnimationFrame reading from the 'engine' ref.
  const [tickCount, setTickCount] = useState(0);

  // Refs for the loop
  const engineRef = useRef(engine);
  const animationFrameRef = useRef<number>();

  // Helper to re-generate map
  const handleGenerate = useCallback(() => {
    const newEngine = createEngine(mapMode);
    setEngine(newEngine);
    engineRef.current = newEngine;
    setTickCount(0);
    setIsRunning(false);
  }, [mapMode]);

  // Handle Map Mode switch -> Auto regenerate
  useEffect(() => {
    handleGenerate();
  }, [mapMode, handleGenerate]);

  // Simulation Loop
  useEffect(() => {
    if (!isRunning) return;

    const loop = () => {
      engineRef.current.tick();

      // Update React state roughly every 60 frames (1 sec) to save UI performance
      // or whenever strictly needed.
      // Actually, let's update every 10 frames so leaderboard feels responsive.
      if (engineRef.current.countries.length > 0) {
           setTickCount(prev => prev + 1);
      }

      animationFrameRef.current = requestAnimationFrame(loop);
    };

    animationFrameRef.current = requestAnimationFrame(loop);

    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [isRunning]);

  // Interaction Handler
  const handleInteract = (x: number, y: number) => {
    const eng = engineRef.current;

    switch (tool) {
      case ToolType.SpawnCountry:
        eng.spawnCountry(x, y);
        setTickCount(c => c + 1); // Force update for leaderboard
        break;
      case ToolType.PlaceCity:
        eng.placeCity(x, y);
        break;
      case ToolType.BrushLand:
        eng.paintTerrain(x, y, TerrainType.Land);
        break;
      case ToolType.BrushMountain:
        eng.paintTerrain(x, y, TerrainType.Mountain);
        break;
      case ToolType.BrushWater:
        eng.paintTerrain(x, y, TerrainType.Water);
        break;
    }
  };

  return (
    <div className="w-screen h-screen bg-slate-950 flex flex-col relative">
      <Interface 
        mapMode={mapMode}
        setMapMode={setMapMode}
        tool={tool}
        setTool={setTool}
        isRunning={isRunning}
        toggleRun={() => setIsRunning(!isRunning)}
        onGenerate={handleGenerate}
      />

      <CanvasRenderer 
        engine={engine} // Pass the instance
        onInteract={handleInteract}
        width={MAP_WIDTH}
        height={MAP_HEIGHT}
      />

      <Leaderboard countries={engine.countries} />
    </div>
  );
}

import React, { useRef, useEffect } from 'react';
import { SimulationEngine } from '../services/SimulationEngine';
import { TerrainType } from '../types';

interface Props {
  engine: SimulationEngine;
  onInteract: (x: number, y: number) => void;
  width: number;
  height: number;
}

export const CanvasRenderer: React.FC<Props> = ({ engine, onInteract, width, height }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Helper to convert hex to rgb
  const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
      r: parseInt(result[1], 16),
      g: parseInt(result[2], 16),
      b: parseInt(result[3], 16)
    } : { r: 0, g: 0, b: 0 };
  };

  // Cache colors to avoid parsing every frame
  const colorCache = useRef<Map<string, {r:number, g:number, b:number}>>(new Map());

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: false }); // Optimize for no alpha
    if (!ctx) return;

    let animationFrameId: number;

    const render = () => {
      const { cells, width: mapW, height: mapH, countries } = engine;

      const imageData = ctx.createImageData(mapW, mapH);
      const data = imageData.data;

      // Update color cache if needed
      countries.forEach(c => {
        if (!colorCache.current.has(c.color)) {
          colorCache.current.set(c.color, hexToRgb(c.color));
        }
      });

      for (let i = 0; i < cells.length; i++) {
        const cell = cells[i];
        const idx = i * 4;

        let r, g, b;

        if (cell.ownerId) {
          // Country Color
          const country = countries.find(c => c.id === cell.ownerId);
          if (country) {
            const rgb = colorCache.current.get(country.color) || {r:255, g:255, b:255};

            // darken based on defense/mountain to give texture
            const variance = cell.terrain === TerrainType.Mountain ? -40 : 0;
            const cityHighlight = cell.cityId ? 40 : 0; // Brighten cities

            r = Math.min(255, Math.max(0, rgb.r + variance + cityHighlight));
            g = Math.min(255, Math.max(0, rgb.g + variance + cityHighlight));
            b = Math.min(255, Math.max(0, rgb.b + variance + cityHighlight));
          } else {
             // Fallback
             r=255; g=255; b=255;
          }
        } else {
          // Terrain Color
          switch (cell.terrain) {
            case TerrainType.Water:
              r = 30; g = 41; b = 59; // Slate-800 ish
              break;
            case TerrainType.Land:
              r = 71; g = 85; b = 105; // Slate-600
              break;
            case TerrainType.Mountain:
              r = 148; g = 163; b = 184; // Slate-400
              break;
            default:
              r = 0; g = 0; b = 0;
          }
        }

        data[idx] = r;
        data[idx + 1] = g;
        data[idx + 2] = b;
        data[idx + 3] = 255; // Alpha
      }

      ctx.putImageData(imageData, 0, 0);
      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
    };
  }, [engine, width, height]);


  // Unified interaction handler for Mouse and Touch
  const handleInteraction = (clientX: number, clientY: number) => {
      if (!canvasRef.current) return;
      const rect = canvasRef.current.getBoundingClientRect();
      const scaleX = engine.width / rect.width;
      const scaleY = engine.height / rect.height;

      const x = Math.floor((clientX - rect.left) * scaleX);
      const y = Math.floor((clientY - rect.top) * scaleY);

      onInteract(x, y);
  };

  const handleMouseDown = (e: React.MouseEvent<HTMLCanvasElement>) => {
      handleInteraction(e.clientX, e.clientY);
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
      if (e.buttons === 1) { // Left click held
          handleInteraction(e.clientX, e.clientY);
      }
  };

  const handleTouchStart = (e: React.TouchEvent<HTMLCanvasElement>) => {
      // e.preventDefault(); // Note: handled by CSS touch-action: none
      if (e.touches.length > 0) {
        handleInteraction(e.touches[0].clientX, e.touches[0].clientY);
      }
  };

  const handleTouchMove = (e: React.TouchEvent<HTMLCanvasElement>) => {
      if (e.touches.length > 0) {
        handleInteraction(e.touches[0].clientX, e.touches[0].clientY);
      }
  };

  return (
    <div ref={containerRef} className="w-full h-full flex items-center justify-center bg-slate-950 overflow-hidden relative shadow-2xl border-y border-slate-800">
      <canvas
        ref={canvasRef}
        width={engine.width}
        height={engine.height}
        className="w-full h-full max-w-[100%] max-h-[100%] object-contain image-pixelated cursor-crosshair touch-none select-none"
        style={{ imageRendering: 'pixelated', touchAction: 'none' }}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
      />
    </div>
  );
};

