export enum TerrainType {
  Water = 0,
  Land = 1,
  Mountain = 2
}

export interface Cell {
  x: number;
  y: number;
  terrain: TerrainType;
  ownerId: number | null; // null = unowned
  cityId: number | null; // null = no city
  defense: number;
}

export interface Country {
  id: number;
  name: string;
  color: string;
  score: number; // Number of cells owned
  money: number;
  isRebel?: boolean;
  capitalId: number | null; // Index of the cell that is capital
}

export interface City {
  id: number;
  name: string;
  cellIndex: number;
  ownerId: number | null;
}

export enum MapMode {
  World = 'World',
  Continents = 'Continents',
  Custom = 'Custom',
}

export enum ToolType {
  Select = 'Select',
  PaintTerritory = 'PaintTerritory', // God mode specific
  BrushLand = 'BrushLand',
  BrushWater = 'BrushWater',
  BrushMountain = 'BrushMountain',
  SpawnCountry = 'SpawnCountry',
  PlaceCity = 'PlaceCity',
  Delete = 'Delete',
}

export interface GameState {
  cells: Cell[];
  countries: Country[];
  cities: City[];
  width: number;
  height: number;
  tick: number;
  isRunning: boolean;
}

import { Cell, Country, City, TerrainType } from '../types';
import { MAP_WIDTH, MAP_HEIGHT } from './MapGenerators';
import { getRandomColor } from '../utils/random';

export class SimulationEngine {
  cells: Cell[];
  countries: Country[];
  cities: City[];
  width: number;
  height: number;

  // Game Logic state
  allianceTracker: Map<string, number> = new Map(); // Key "id1-id2", Val: ticks of peace

  constructor(cells: Cell[], width: number, height: number) {
    this.cells = cells;
    this.width = width;
    this.height = height;
    this.countries = [];
    this.cities = [];
  }

  // --- Helpers ---
  getIndex(x: number, y: number): number {
    if (x < 0 || x >= this.width || y < 0 || y >= this.height) return -1;
    return y * this.width + x;
  }

  getNeighbors(index: number): number[] {
    const x = index % this.width;
    const y = Math.floor(index / this.width);
    const neighbors = [];

    const dirs = [[0,1], [0,-1], [1,0], [-1,0]];
    for(const [dx, dy] of dirs) {
      const idx = this.getIndex(x + dx, y + dy);
      if (idx !== -1) neighbors.push(idx);
    }
    return neighbors;
  }

  // --- Actions ---

  spawnCountry(x: number, y: number, name?: string, color?: string): void {
    const idx = this.getIndex(x, y);
    if (idx === -1) return;

    const cell = this.cells[idx];
    if (cell.terrain === TerrainType.Water) return;

    // Check if already owned
    if (cell.ownerId !== null) return;

    const newId = this.countries.length > 0 ? Math.max(...this.countries.map(c => c.id)) + 1 : 1;
    const finalColor = color || getRandomColor();

    const newCountry: Country = {
      id: newId,
      name: name || `Nation ${newId}`,
      color: finalColor,
      score: 1,
      money: 0,
      capitalId: idx,
    };

    this.countries.push(newCountry);
    cell.ownerId = newId;
    cell.defense = 100; // Strong start
  }

  // God Mode: Set ownership directly
  setCellOwner(x: number, y: number, countryId: number): void {
    const idx = this.getIndex(x, y);
    if (idx === -1) return;
    const cell = this.cells[idx];

    if (cell.terrain === TerrainType.Water) return;

    cell.ownerId = countryId;
    cell.defense = 100;
  }

  // God Mode: Delete Country
  deleteCountry(id: number): void {
      this.countries = this.countries.filter(c => c.id !== id);
      // Clear cells
      for (const cell of this.cells) {
          if (cell.ownerId === id) {
              cell.ownerId = null;
              cell.defense = 0;
          }
      }
      // Clear cities ownership
      for (const city of this.cities) {
          if (city.ownerId === id) city.ownerId = null;
      }
  }

  // God Mode: Rename/Recolor
  updateCountry(id: number, updates: Partial<Country>) {
      const country = this.countries.find(c => c.id === id);
      if (country) {
          Object.assign(country, updates);
      }
  }

  placeCity(x: number, y: number): void {
     const idx = this.getIndex(x, y);
     if (idx === -1) return;
     const cell = this.cells[idx];
     if (cell.terrain === TerrainType.Water) return;

     // Prevent duplicates
     if (cell.cityId !== null) return;

     const cityId = this.cities.length + 1;
     this.cities.push({
         id: cityId,
         name: `City ${cityId}`,
         cellIndex: idx,
         ownerId: cell.ownerId
     });
     cell.cityId = cityId;
     cell.defense += 50; // Bonus defense
  }

  paintTerrain(x: number, y: number, type: TerrainType): void {
      const idx = this.getIndex(x, y);
      if (idx !== -1) {
          this.cells[idx].terrain = type;
          // Reset ownership if turning to water
          if (type === TerrainType.Water) {
              this.cells[idx].ownerId = null;
              this.cells[idx].cityId = null;
              this.cells[idx].defense = 0;
          }
      }
  }

  getOwnerAt(x: number, y: number): number | null {
      const idx = this.getIndex(x, y);
      if (idx === -1) return null;
      return this.cells[idx].ownerId;
  }

  // --- Tick Logic ---

  tick(): void {
    // We shuffle a list of indices to process to avoid directional bias
    // Optimization: Only process border cells? For now, brute force is fine for 15k cells.
    // Optimization 2: Random sampling. We don't need to update EVERY cell every tick.
    // Let's update 10% of the map per tick for performance and "organic" feel.

    const numUpdates = Math.floor(this.cells.length * 0.2); 

    for (let i = 0; i < numUpdates; i++) {
        const idx = Math.floor(Math.random() * this.cells.length);
        this.processCell(idx);
    }

    // Occasional Global Checks (Revolts, Alliances)
    if (Math.random() < 0.01) {
        this.checkRevolts();
    }

    this.updateScores();
  }

  processCell(idx: number) {
      const cell = this.cells[idx];

      // Only owned land acts
      if (cell.ownerId === null || cell.terrain === TerrainType.Water) return;

      const neighbors = this.getNeighbors(idx);
      const neighborIdx = neighbors[Math.floor(Math.random() * neighbors.length)];
      const target = this.cells[neighborIdx];

      // Interaction Logic
      if (target.terrain === TerrainType.Water) return;

      // 1. Expansion (Claim Empty Land)
      if (target.ownerId === null) {
          // Mountains are harder to claim
          const difficulty = target.terrain === TerrainType.Mountain ? 0.1 : 0.8;
          if (Math.random() < difficulty) {
              target.ownerId = cell.ownerId;
              target.defense = 10;
          }
          return;
      }

      // 2. War (Attack Enemy)
      if (target.ownerId !== cell.ownerId) {
          // Check Alliance (Simplified: 5% chance to ignore war if not forced)
          // Real alliance logic would check the alliance map.

          // Attack calculation
          // Attacker strength: Random + Defense support
          // Defender strength: Random + Defense

          const attackRoll = Math.random() * (cell.defense + 50);
          const defenseRoll = Math.random() * (target.defense + (target.cityId ? 50 : 0) + (target.terrain === TerrainType.Mountain ? 30 : 0));

          if (attackRoll > defenseRoll) {
              // Successful invasion
              target.defense -= 20;
              if (target.defense <= 0) {
                  target.ownerId = cell.ownerId;
                  target.defense = 20; // Reset defense for new owner

                  // Capture City Bonus
                  if (target.cityId) {
                      // Boost all cells of this country? Or just local?
                      cell.defense += 50; 
                  }
              }
          } else {
              // Failed attack, defender hardens
              target.defense = Math.min(target.defense + 5, 100);
          }
      } else {
          // 3. Reinforce (Heal own land)
          if (target.defense < 100) {
              target.defense += 1;
          }
      }
  }

  updateScores() {
      // Reset scores
      const scores = new Map<number, number>();
      for(const c of this.countries) scores.set(c.id, 0);

      for(const cell of this.cells) {
          if (cell.ownerId) {
              const current = scores.get(cell.ownerId) || 0;
              scores.set(cell.ownerId, current + 1);
          }
      }

      for(const c of this.countries) {
          c.score = scores.get(c.id) || 0;
      }

      // Remove dead countries
      // this.countries = this.countries.filter(c => c.score > 0);
  }

  checkRevolts() {
    // Very expensive, run rarely.
    // BFS from Capital to see if territory is contiguous.
    // If not, split off.

    // Simplified: Just check if a random country is fragmented.
    if (this.countries.length === 0) return;
    const country = this.countries[Math.floor(Math.random() * this.countries.length)];
    if (country.score < 10) return; // Too small to revolt
    if (!country.capitalId) return;

    // BFS
    const queue = [country.capitalId];
    const visited = new Set<number>();
    visited.add(country.capitalId);

    // Safety break
    let limit = 0;
    while(queue.length > 0 && limit < 5000) {
        limit++;
        const curr = queue.shift()!;
        const neighbors = this.getNeighbors(curr);
        for(const n of neighbors) {
            if (this.cells[n].ownerId === country.id && !visited.has(n)) {
                visited.add(n);
                queue.push(n);
            }
        }
    }

    // If visited count < total score, we have disconnected lands
    if (visited.size < country.score * 0.8) { // If less than 80% is connected to capital
        // Create rebel faction
        const rebelId = this.countries.length > 0 ? Math.max(...this.countries.map(c => c.id)) + 1 : 1;
        const rebelColor = getRandomColor();
        this.countries.push({
            id: rebelId,
            name: `${country.name} Separatists`,
            color: rebelColor,
            score: 0,
            money: 0,
            isRebel: true,
            capitalId: null
        });

        // Convert unvisited cells to rebels
        for(let i=0; i<this.cells.length; i++) {
            if (this.cells[i].ownerId === country.id && !visited.has(i)) {
                this.cells[i].ownerId = rebelId;
                // Set first rebel cell as capital
                if (this.countries[this.countries.length-1].capitalId === null) {
                    this.countries[this.countries.length-1].capitalId = i;
                }
            }
        }
    }
  }
}

