import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SimulationEngine } from './services/SimulationEngine';
import { generateWorld, generateContinents, generateCustom, MAP_WIDTH, MAP_HEIGHT } from './services/MapGenerators';
import { CanvasRenderer } from './components/CanvasRenderer';
import { Interface } from './components/Interface';
import { Leaderboard } from './components/Leaderboard';
import { SpawnModal } from './components/SpawnModal';
import { CountryInspector } from './components/CountryInspector';
import { MapMode, ToolType, TerrainType, Country } from './types';

// Initial Engine Setup
const createEngine = (mode: MapMode) => {
  let cells;
  switch (mode) {
    case MapMode.Continents: cells = generateContinents(); break;
    case MapMode.Custom: cells = generateCustom(); break;
    case MapMode.World: default: cells = generateWorld(); break;
  }
  return new SimulationEngine(cells, MAP_WIDTH, MAP_HEIGHT);
};

export default function App() {
  const [mapMode, setMapMode] = useState<MapMode>(MapMode.World);
  const [tool, setTool] = useState<ToolType>(ToolType.SpawnCountry);
  const [isRunning, setIsRunning] = useState(false);
  const [engine, setEngine] = useState<SimulationEngine>(() => createEngine(MapMode.World));

  // UI State
  const [tickCount, setTickCount] = useState(0);

  // Modals / Inspectors
  const [spawnLocation, setSpawnLocation] = useState<{x: number, y: number} | null>(null);
  const [selectedCountryId, setSelectedCountryId] = useState<number | null>(null);
  const [godModePaintingId, setGodModePaintingId] = useState<number | null>(null);

  // Refs for the loop
  const engineRef = useRef(engine);
  const animationFrameRef = useRef<number>();

  // Helper to re-generate map
  const handleGenerate = useCallback(() => {
    const newEngine = createEngine(mapMode);
    setEngine(newEngine);
    engineRef.current = newEngine;
    setTickCount(0);
    setIsRunning(false);
    setSelectedCountryId(null);
    setGodModePaintingId(null);
  }, [mapMode]);

  useEffect(() => {
    handleGenerate();
  }, [mapMode, handleGenerate]);

  // Simulation Loop
  useEffect(() => {
    if (!isRunning) return;
    const loop = () => {
      engineRef.current.tick();
      if (engineRef.current.countries.length > 0) {
           setTickCount(prev => prev + 1);
      }
      animationFrameRef.current = requestAnimationFrame(loop);
    };
    animationFrameRef.current = requestAnimationFrame(loop);
    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [isRunning]);

  // Handle Canvas Interactivity
  const handleInteract = (x: number, y: number) => {
    const eng = engineRef.current;

    // Override if in God Mode Paint State
    if (godModePaintingId !== null && tool === ToolType.PaintTerritory) {
         eng.setCellOwner(x, y, godModePaintingId);
         return;
    }

    switch (tool) {
      case ToolType.Select: {
          const owner = eng.getOwnerAt(x, y);
          if (owner !== null) {
              setSelectedCountryId(owner);
              setGodModePaintingId(null); // Reset painting when selecting new
          } else {
              setSelectedCountryId(null);
          }
          break;
      }
      case ToolType.SpawnCountry:
        // Open Modal instead of spawning immediately
        setSpawnLocation({ x, y });
        break;
      case ToolType.PlaceCity:
        eng.placeCity(x, y);
        break;
      case ToolType.BrushLand:
        eng.paintTerrain(x, y, TerrainType.Land);
        break;
      case ToolType.BrushMountain:
        eng.paintTerrain(x, y, TerrainType.Mountain);
        break;
      case ToolType.BrushWater:
        eng.paintTerrain(x, y, TerrainType.Water);
        break;
      case ToolType.PaintTerritory:
         // Handled above in godMode check, but fallback here
         if (selectedCountryId) eng.setCellOwner(x, y, selectedCountryId);
         break;
    }
  };

  // Modal Callbacks
  const handleSpawnConfirm = (name: string, color: string) => {
      if (spawnLocation) {
          engineRef.current.spawnCountry(spawnLocation.x, spawnLocation.y, name, color);
          setTickCount(c => c + 1);
          setSpawnLocation(null);
      }
  };

  // God Mode Callbacks
  const handleDeleteCountry = (id: number) => {
      engineRef.current.deleteCountry(id);
      setSelectedCountryId(null);
      setTickCount(c => c + 1);
  };

  const handleUpdateCountry = (id: number, updates: Partial<Country>) => {
      engineRef.current.updateCountry(id, updates);
      setTickCount(c => c + 1);
  };

  const togglePaintTerritory = (id: number) => {
      if (godModePaintingId === id) {
          // Stop painting
          setGodModePaintingId(null);
          setTool(ToolType.Select);
      } else {
          // Start painting
          setGodModePaintingId(id);
          setTool(ToolType.PaintTerritory);
      }
  };

  return (
    <div className="w-screen h-screen bg-slate-950 flex flex-col relative">
      <Interface 
        mapMode={mapMode}
        setMapMode={setMapMode}
        tool={tool}
        setTool={(t) => {
             setTool(t);
             // If switching away from paint territory manually, stop painting
             if (t !== ToolType.PaintTerritory) setGodModePaintingId(null);
        }}
        isRunning={isRunning}
        toggleRun={() => setIsRunning(!isRunning)}
        onGenerate={handleGenerate}
      />

      <CanvasRenderer 
        engine={engine}
        onInteract={handleInteract}
        width={MAP_WIDTH}
        height={MAP_HEIGHT}
      />

      <Leaderboard countries={engine.countries} />

      {spawnLocation && (
          <SpawnModal 
              x={spawnLocation.x} 
              y={spawnLocation.y} 
              onConfirm={handleSpawnConfirm} 
              onCancel={() => setSpawnLocation(null)}
          />
      )}

      {selectedCountryId && (
          <CountryInspector 
              country={engine.countries.find(c => c.id === selectedCountryId)!}
              onClose={() => setSelectedCountryId(null)}
              onDelete={handleDeleteCountry}
              onUpdate={handleUpdateCountry}
              onPaintTerritory={togglePaintTerritory}
              isPainting={godModePaintingId === selectedCountryId}
          />
      )}
    </div>
  );
}

export enum TerrainType {
  Water = 0,
  Land = 1,
  Mountain = 2
}

export interface Cell {
  x: number;
  y: number;
  terrain: TerrainType;
  ownerId: number | null; // null = unowned
  cityId: number | null; // null = no city
  defense: number;
}

export interface Country {
  id: number;
  name: string;
  color: string;
  score: number; // Number of cells owned
  money: number;
  isRebel?: boolean;
  capitalId: number | null; // Index of the cell that is capital
}

export interface City {
  id: number;
  name: string;
  cellIndex: number;
  ownerId: number | null;
}

export interface WorldEvent {
  id: number;
  message: string;
  type: 'war' | 'peace' | 'annex' | 'spawn' | 'revolt';
  timestamp: number; // Game tick
}

export enum MapMode {
  World = 'World',
  Continents = 'Continents',
  Custom = 'Custom',
}

export enum ToolType {
  Select = 'Select',
  PaintTerritory = 'PaintTerritory', // God mode specific
  BrushLand = 'BrushLand',
  BrushWater = 'BrushWater',
  BrushMountain = 'BrushMountain',
  SpawnCountry = 'SpawnCountry',
  PlaceCity = 'PlaceCity',
  Delete = 'Delete',
}

export interface GameState {
  cells: Cell[];
  countries: Country[];
  cities: City[];
  width: number;
  height: number;
  tick: number;
  isRunning: boolean;
}

import { Cell, Country, City, TerrainType, WorldEvent } from '../types';
import { MAP_WIDTH, MAP_HEIGHT } from './MapGenerators';
import { getRandomColor } from '../utils/random';

const CITY_NAMES_PREFIX = ['New', 'Old', 'Fort', 'Saint', 'Port', 'Mount', 'Lake', 'Grand', 'Little'];
const CITY_NAMES_SUFFIX = ['grad', 'town', 'ville', 'burg', 'ia', 'field', 'haven', 'side', 'wood'];

const generateCityName = () => {
  const p = CITY_NAMES_PREFIX[Math.floor(Math.random() * CITY_NAMES_PREFIX.length)];
  const s = CITY_NAMES_SUFFIX[Math.floor(Math.random() * CITY_NAMES_SUFFIX.length)];
  return `${p} ${s}`;
};

export class SimulationEngine {
  cells: Cell[];
  countries: Country[];
  cities: City[];
  events: WorldEvent[];
  width: number;
  height: number;
  tickCount: number = 0;

  // Game Logic state
  activeWars: Set<string> = new Set(); // Key "minId-maxId"

  constructor(cells: Cell[], width: number, height: number) {
    this.cells = cells;
    this.width = width;
    this.height = height;
    this.countries = [];
    this.cities = [];
    this.events = [];
  }

  // --- Helpers ---
  getIndex(x: number, y: number): number {
    if (x < 0 || x >= this.width || y < 0 || y >= this.height) return -1;
    return y * this.width + x;
  }

  getNeighbors(index: number): number[] {
    const x = index % this.width;
    const y = Math.floor(index / this.width);
    const neighbors = [];

    const dirs = [[0,1], [0,-1], [1,0], [-1,0]];
    for(const [dx, dy] of dirs) {
      const idx = this.getIndex(x + dx, y + dy);
      if (idx !== -1) neighbors.push(idx);
    }
    return neighbors;
  }

  logEvent(message: string, type: WorldEvent['type']) {
    this.events.unshift({
        id: Math.random(),
        message,
        type,
        timestamp: this.tickCount
    });
    if (this.events.length > 50) this.events.pop();
  }

  getWarKey(id1: number, id2: number) {
      return id1 < id2 ? `${id1}-${id2}` : `${id2}-${id1}`;
  }

  // --- Actions ---

  spawnCountry(x: number, y: number, name?: string, color?: string): void {
    const idx = this.getIndex(x, y);
    if (idx === -1) return;

    const cell = this.cells[idx];
    if (cell.terrain === TerrainType.Water) return;

    // Check if already owned
    if (cell.ownerId !== null) return;

    const newId = this.countries.length > 0 ? Math.max(...this.countries.map(c => c.id)) + 1 : 1;
    const finalColor = color || getRandomColor();
    const finalName = name || `Nation ${newId}`;

    const newCountry: Country = {
      id: newId,
      name: finalName,
      color: finalColor,
      score: 1,
      money: 0,
      capitalId: idx,
    };

    this.countries.push(newCountry);
    cell.ownerId = newId;
    cell.defense = 100; // Strong start

    this.placeCity(x, y, `${finalName} Capital`);
    this.logEvent(`${finalName} has been founded.`, 'spawn');
  }

  // God Mode: Set ownership directly
  setCellOwner(x: number, y: number, countryId: number): void {
    const idx = this.getIndex(x, y);
    if (idx === -1) return;
    const cell = this.cells[idx];

    if (cell.terrain === TerrainType.Water) return;

    cell.ownerId = countryId;
    cell.defense = 100;
  }

  // God Mode: Delete Country
  deleteCountry(id: number): void {
      const country = this.countries.find(c => c.id === id);
      if (country) {
        this.logEvent(`${country.name} was removed by divine intervention.`, 'annex');
      }
      this.countries = this.countries.filter(c => c.id !== id);
      // Clear cells
      for (const cell of this.cells) {
          if (cell.ownerId === id) {
              cell.ownerId = null;
              cell.defense = 0;
          }
      }
      // Clear cities ownership
      for (const city of this.cities) {
          if (city.ownerId === id) city.ownerId = null;
      }
  }

  // God Mode: Rename/Recolor
  updateCountry(id: number, updates: Partial<Country>) {
      const country = this.countries.find(c => c.id === id);
      if (country) {
          Object.assign(country, updates);
      }
  }

  placeCity(x: number, y: number, name?: string): void {
     const idx = this.getIndex(x, y);
     if (idx === -1) return;
     const cell = this.cells[idx];
     if (cell.terrain === TerrainType.Water) return;

     // Prevent duplicates
     if (cell.cityId !== null) return;

     const cityId = this.cities.length + 1;
     this.cities.push({
         id: cityId,
         name: name || generateCityName(),
         cellIndex: idx,
         ownerId: cell.ownerId
     });
     cell.cityId = cityId;
     cell.defense += 50; // Bonus defense
  }

  paintTerrain(x: number, y: number, type: TerrainType): void {
      const idx = this.getIndex(x, y);
      if (idx !== -1) {
          this.cells[idx].terrain = type;
          // Reset ownership if turning to water
          if (type === TerrainType.Water) {
              this.cells[idx].ownerId = null;
              this.cells[idx].cityId = null;
              this.cells[idx].defense = 0;
          }
      }
  }

  getOwnerAt(x: number, y: number): number | null {
      const idx = this.getIndex(x, y);
      if (idx === -1) return null;
      return this.cells[idx].ownerId;
  }

  // --- Tick Logic ---

  tick(): void {
    this.tickCount++;
    const numUpdates = Math.floor(this.cells.length * 0.2); 

    for (let i = 0; i < numUpdates; i++) {
        const idx = Math.floor(Math.random() * this.cells.length);
        this.processCell(idx);
    }

    // Occasional Global Checks (Revolts, Alliances)
    if (Math.random() < 0.01) {
        this.checkRevolts();
    }

    this.updateScores();
  }

  processCell(idx: number) {
      const cell = this.cells[idx];

      // Only owned land acts
      if (cell.ownerId === null || cell.terrain === TerrainType.Water) return;

      const neighbors = this.getNeighbors(idx);
      const neighborIdx = neighbors[Math.floor(Math.random() * neighbors.length)];
      const target = this.cells[neighborIdx];

      // Interaction Logic
      if (target.terrain === TerrainType.Water) return;

      // 1. Expansion (Claim Empty Land)
      if (target.ownerId === null) {
          // Mountains are harder to claim
          const difficulty = target.terrain === TerrainType.Mountain ? 0.1 : 0.8;
          if (Math.random() < difficulty) {
              target.ownerId = cell.ownerId;
              target.defense = 10;
          }
          return;
      }

      // 2. War (Attack Enemy)
      if (target.ownerId !== cell.ownerId) {
          // Check War Start
          const warKey = this.getWarKey(cell.ownerId, target.ownerId);
          if (!this.activeWars.has(warKey)) {
              this.activeWars.add(warKey);
              const c1 = this.countries.find(c => c.id === cell.ownerId);
              const c2 = this.countries.find(c => c.id === target.ownerId);
              if (c1 && c2) {
                  this.logEvent(`War broke out between ${c1.name} and ${c2.name}!`, 'war');
              }
          }

          const attackRoll = Math.random() * (cell.defense + 50);
          const defenseRoll = Math.random() * (target.defense + (target.cityId ? 50 : 0) + (target.terrain === TerrainType.Mountain ? 30 : 0));

          if (attackRoll > defenseRoll) {
              // Successful invasion
              target.defense -= 20;
              if (target.defense <= 0) {
                  target.ownerId = cell.ownerId;
                  target.defense = 20; // Reset defense for new owner

                  // Capture City Bonus
                  if (target.cityId) {
                      cell.defense += 50; 
                      const city = this.cities.find(c => c.id === target.cityId);
                      if (city) {
                          city.ownerId = cell.ownerId;
                          // Optional: Log city capture?
                          // this.logEvent(`${city.name} was captured!`, 'war');
                      }
                  }
              }
          } else {
              // Failed attack, defender hardens
              target.defense = Math.min(target.defense + 5, 100);
          }
      } else {
          // 3. Reinforce (Heal own land)
          if (target.defense < 100) {
              target.defense += 1;
          }
      }
  }

  updateScores() {
      // Reset scores
      const scores = new Map<number, number>();
      for(const cell of this.cells) {
          if (cell.ownerId) {
              const current = scores.get(cell.ownerId) || 0;
              scores.set(cell.ownerId, current + 1);
          }
      }

      const survivingCountries: Country[] = [];
      for(const c of this.countries) {
          const newScore = scores.get(c.id) || 0;

          if (c.score > 0 && newScore === 0) {
              // Country died this tick
              this.logEvent(`${c.name} has been annexed and wiped off the map.`, 'annex');
          } else if (newScore > 0 || c.score === 0) {
               // Alive or just spawned (score 0 but in list? spawn usually gives 1 score immediately)
               c.score = newScore;
               survivingCountries.push(c);
          }
      }
      this.countries = survivingCountries;
  }

  checkRevolts() {
    if (this.countries.length === 0) return;
    const country = this.countries[Math.floor(Math.random() * this.countries.length)];
    if (country.score < 10) return; // Too small to revolt
    if (!country.capitalId) return;

    // BFS
    const queue = [country.capitalId];
    const visited = new Set<number>();
    visited.add(country.capitalId);

    let limit = 0;
    while(queue.length > 0 && limit < 5000) {
        limit++;
        const curr = queue.shift()!;
        const neighbors = this.getNeighbors(curr);
        for(const n of neighbors) {
            if (this.cells[n].ownerId === country.id && !visited.has(n)) {
                visited.add(n);
                queue.push(n);
            }
        }
    }

    // If visited count < total score, we have disconnected lands
    if (visited.size < country.score * 0.8) {
        const rebelId = this.countries.length > 0 ? Math.max(...this.countries.map(c => c.id)) + 1 : 1;
        const rebelColor = getRandomColor();
        const rebelName = `${country.name} Separatists`;

        const newRebel: Country = {
            id: rebelId,
            name: rebelName,
            color: rebelColor,
            score: 0,
            money: 0,
            isRebel: true,
            capitalId: null
        };
        this.countries.push(newRebel);

        // Convert unvisited cells to rebels
        let convertedCount = 0;
        for(let i=0; i<this.cells.length; i++) {
            if (this.cells[i].ownerId === country.id && !visited.has(i)) {
                this.cells[i].ownerId = rebelId;
                convertedCount++;
                if (this.countries[this.countries.length-1].capitalId === null) {
                    this.countries[this.countries.length-1].capitalId = i;
                    // Make new capital
                    this.placeCity(this.cells[i].x, this.cells[i].y, `${rebelName} HQ`);
                }
            }
        }

        if (convertedCount > 0) {
             this.logEvent(`Rebellion! ${rebelName} have risen up against ${country.name}.`, 'revolt');
        }
    }
  }
}

import React, { useEffect, useRef } from 'react';
import { WorldEvent } from '../types';
import { Scroll, Skull, Swords, Flag, AlertTriangle } from 'lucide-react';

interface Props {
  events: WorldEvent[];
