        </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { SimulationEngine } from '../services/SimulationEngine';
import { TerrainType } from '../types';

interface Props {
  engine: SimulationEngine;
  onInteract: (x: number, y: number) => void;
  width: number;
  height: number;
}

export const CanvasRenderer: React.FC<Props> = ({ engine, onInteract, width, height }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const bufferCanvasRef = useRef<HTMLCanvasElement | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Viewport State (Camera)
  const [viewport, setViewport] = useState({ x: 0, y: 0, scale: 4 }); 

  // Interaction State
  const isDragging = useRef(false);
  const lastPos = useRef<{x: number, y: number} | null>(null);
  const touchDist = useRef<number | null>(null); // For pinch zoom

  // Cache colors
  const colorCache = useRef<Map<string, {r:number, g:number, b:number}>>(new Map());

  // Init buffer once
  useEffect(() => {
    if (!bufferCanvasRef.current) {
        const buf = document.createElement('canvas');
        buf.width = width;
        buf.height = height;
        bufferCanvasRef.current = buf;
    }
  }, [width, height]);

  // Render Loop
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;

    let animationFrameId: number;

    const render = () => {
      // 1. Render Map to Buffer (Low Res)
      const buffer = bufferCanvasRef.current;
      if (buffer) {
          const bCtx = buffer.getContext('2d');
          if (bCtx) {
             const { cells, countries } = engine;
             const imageData = bCtx.createImageData(width, height);
             const data = imageData.data;

             // Update colors
             const hexToRgb = (hex: string) => {
                const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
                return result ? {
                  r: parseInt(result[1], 16),
                  g: parseInt(result[2], 16),
                  b: parseInt(result[3], 16)
                } : { r: 0, g: 0, b: 0 };
              };

             countries.forEach(c => {
                 if (!colorCache.current.has(c.color)) {
                     colorCache.current.set(c.color, hexToRgb(c.color));
                 }
             });

             for (let i = 0; i < cells.length; i++) {
                 const cell = cells[i];
                 const idx = i * 4;
                 let r, g, b;

                 if (cell.ownerId) {
                     const country = countries.find(c => c.id === cell.ownerId);
                     if (country) {
                         const rgb = colorCache.current.get(country.color) || {r:255,g:255,b:255};
                         const variance = cell.terrain === TerrainType.Mountain ? -40 : 0;
                         const cityHighlight = cell.cityId ? 40 : 0;
                         r = Math.min(255, Math.max(0, rgb.r + variance + cityHighlight));
                         g = Math.min(255, Math.max(0, rgb.g + variance + cityHighlight));
                         b = Math.min(255, Math.max(0, rgb.b + variance + cityHighlight));
                     } else {
                         r=255; g=255; b=255; // Error pink
                     }
                 } else {
                     switch (cell.terrain) {
                         case TerrainType.Water: r=30; g=41; b=59; break;
                         case TerrainType.Land: r=71; g=85; b=105; break;
                         case TerrainType.Mountain: r=148; g=163; b=184; break;
                         default: r=0; g=0; b=0;
                     }
                 }
                 data[idx] = r; data[idx+1] = g; data[idx+2] = b; data[idx+3] = 255;
             }
             bCtx.putImageData(imageData, 0, 0);
          }
      }

      // 2. Render Buffer to Screen (Transformed)
      if (buffer) {
          // Clear Screen
          ctx.fillStyle = '#020617'; // bg-slate-950
          ctx.fillRect(0, 0, canvas.width, canvas.height);

          ctx.save();
          // Apply Camera Transform
          ctx.translate(viewport.x, viewport.y);
          ctx.scale(viewport.scale, viewport.scale);

          // Draw buffer without smoothing for pixel art look
          ctx.imageSmoothingEnabled = false;
          ctx.drawImage(buffer, 0, 0);

          ctx.restore();

          // 3. Render City Names (Overlay)
          // Only if zoomed in enough to be readable
          if (viewport.scale > 8) {
              ctx.font = 'bold 10px monospace';
              ctx.textAlign = 'center';
              ctx.textBaseline = 'bottom';

              const { cities } = engine;
              for(const city of cities) {
                   const cx = city.cellIndex % width;
                   const cy = Math.floor(city.cellIndex / width);

                   // Project to screen
                   const screenX = cx * viewport.scale + viewport.x + (viewport.scale/2);
                   const screenY = cy * viewport.scale + viewport.y;

                   // Cull offscreen
                   if (screenX < -50 || screenX > canvas.width + 50 || screenY < -50 || screenY > canvas.height + 50) continue;

                   // Draw Label Background
                   const text = city.name;
                   const measure = ctx.measureText(text);
                   const w = measure.width + 8;
                   const h = 14;

                   ctx.fillStyle = 'rgba(0,0,0,0.6)';
                   ctx.fillRect(screenX - w/2, screenY - h - 4, w, h);

                   // Draw Text
                   ctx.fillStyle = '#ffffff';
                   ctx.fillText(text, screenX, screenY - 6);
              }
          }
      }

      animationFrameId = requestAnimationFrame(render);
    };
    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [engine, viewport, width, height]);


  // --- Event Handling ---

  // Convert Screen Coords to Map Coords
  const toWorld = (sx: number, sy: number) => {
      const rect = canvasRef.current!.getBoundingClientRect();
      const x = (sx - rect.left - viewport.x) / viewport.scale;
      const y = (sy - rect.top - viewport.y) / viewport.scale;
      return { x: Math.floor(x), y: Math.floor(y) };
  };

  const handleWheel = (e: React.WheelEvent) => {
      e.preventDefault();
      // Zoom towards pointer
      const rect = canvasRef.current!.getBoundingClientRect();
      const mouseX = e.clientX - rect.left;
      const mouseY = e.clientY - rect.top;

      const zoomFactor = -e.deltaY * 0.001;
      const newScale = Math.min(Math.max(0.5, viewport.scale * (1 + zoomFactor)), 30);

      const scaleRatio = newScale / viewport.scale;

      // Calculate new offset to keep mouseX/Y at same world position
      const newX = mouseX - (mouseX - viewport.x) * scaleRatio;
      const newY = mouseY - (mouseY - viewport.y) * scaleRatio;

      setViewport({ x: newX, y: newY, scale: newScale });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
      if (e.button === 1 || e.shiftKey) { // Middle click or Shift+Click -> Pan
          isDragging.current = true;
          lastPos.current = { x: e.clientX, y: e.clientY };
      } else if (e.button === 0) { // Left Click -> Interact
          const pos = toWorld(e.clientX, e.clientY);
          onInteract(pos.x, pos.y);
          // Also allow dragging to paint if tool supports it
          isDragging.current = true; 
          lastPos.current = { x: e.clientX, y: e.clientY };
      }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
      if (!isDragging.current) return;

      // If Middle Mouse or Shift -> Pan
      if (e.buttons === 4 || e.shiftKey) {
          const dx = e.clientX - lastPos.current!.x;
          const dy = e.clientY - lastPos.current!.y;
          setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
          lastPos.current = { x: e.clientX, y: e.clientY };
      } else if (e.buttons === 1) {
          // Left Drag -> Interact (Paint)
          const pos = toWorld(e.clientX, e.clientY);
          onInteract(pos.x, pos.y);
          lastPos.current = { x: e.clientX, y: e.clientY };
      }
  };

  const handleMouseUp = () => {
      isDragging.current = false;
      lastPos.current = null;
  };

  // Touch Handling
  const handleTouchStart = (e: React.TouchEvent) => {
      if (e.touches.length === 2) {
          // Pinch Zoom Start
          const t1 = e.touches[0];
          const t2 = e.touches[1];
          const dist = Math.hypot(t1.clientX - t2.clientX, t1.clientY - t2.clientY);
          touchDist.current = dist;
          lastPos.current = { 
            x: (t1.clientX + t2.clientX) / 2, 
            y: (t1.clientY + t2.clientY) / 2 
          };
      } else if (e.touches.length === 1) {
          // Interact
          const t = e.touches[0];
          const pos = toWorld(t.clientX, t.clientY);
          onInteract(pos.x, pos.y);
          isDragging.current = true;
          lastPos.current = { x: t.clientX, y: t.clientY };
      }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
      if (e.touches.length === 2) {
          // Pinch Zoom / Pan
          const t1 = e.touches[0];
          const t2 = e.touches[1];
          const dist = Math.hypot(t1.clientX - t2.clientX, t1.clientY - t2.clientY);
          const center = { x: (t1.clientX + t2.clientX) / 2, y: (t1.clientY + t2.clientY) / 2 };

          if (touchDist.current && lastPos.current) {
              // Zoom
              const scaleFactor = dist / touchDist.current;
              const newScale = Math.min(Math.max(0.5, viewport.scale * scaleFactor), 30);

              // Pan
              const dx = center.x - lastPos.current.x;
              const dy = center.y - lastPos.current.y;

              // Simplified: Apply pan then scale
              const rect = canvasRef.current!.getBoundingClientRect();
              const pinchX = center.x - rect.left;
              const pinchY = center.y - rect.top;

              const scaleRatio = newScale / viewport.scale;
              const newX = pinchX - (pinchX - (viewport.x + dx)) * scaleRatio;
              const newY = pinchY - (pinchY - (viewport.y + dy)) * scaleRatio;

              setViewport({ x: newX, y: newY, scale: newScale });
          }

          touchDist.current = dist;
          lastPos.current = center;
      } else if (e.touches.length === 1 && isDragging.current) {
          // Drag Interact
          const t = e.touches[0];
          const pos = toWorld(t.clientX, t.clientY);
          onInteract(pos.x, pos.y);
      }
  };

  const handleTouchEnd = () => {
      isDragging.current = false;
      touchDist.current = null;
      lastPos.current = null;
  };

  // Resize handler
  useEffect(() => {
    const handleResize = () => {
       if (containerRef.current && canvasRef.current) {
           canvasRef.current.width = containerRef.current.clientWidth;
           canvasRef.current.height = containerRef.current.clientHeight;

           // Center initially
           setViewport({
               x: (containerRef.current.clientWidth - width * 4) / 2,
               y: (containerRef.current.clientHeight - height * 4) / 2,
               scale: 4
           });
       }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); // call once
    return () => window.removeEventListener('resize', handleResize);
  }, [width, height]);


  return (
    <div ref={containerRef} className="w-full h-full flex bg-slate-950 overflow-hidden relative border-y border-slate-800 cursor-crosshair">
      <canvas
        ref={canvasRef}
        className="block touch-none select-none outline-none"
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
      />

      {/* Zoom HUD */}
      <div className="absolute bottom-4 right-4 bg-black/50 backdrop-blur rounded px-2 py-1 text-xs text-slate-400 font-mono pointer-events-none z-10">
          {Math.round(viewport.scale * 100)}%
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SimulationEngine } from './services/SimulationEngine';
import { generateWorld, generateContinents, generateCustom, MAP_WIDTH, MAP_HEIGHT } from './services/MapGenerators';
import { CanvasRenderer } from './components/CanvasRenderer';
import { Interface } from './components/Interface';
import { Leaderboard } from './components/Leaderboard';
import { SpawnModal } from './components/SpawnModal';
import { CountryInspector } from './components/CountryInspector';
import { EventLog } from './components/EventLog';
import { MapMode, ToolType, TerrainType, Country } from './types';

// Initial Engine Setup
const createEngine = (mode: MapMode) => {
  let cells;
  switch (mode) {
    case MapMode.Continents: cells = generateContinents(); break;
    case MapMode.Custom: cells = generateCustom(); break;
    case MapMode.World: default: cells = generateWorld(); break;
  }
  return new SimulationEngine(cells, MAP_WIDTH, MAP_HEIGHT);
};

export default function App() {
  const [mapMode, setMapMode] = useState<MapMode>(MapMode.World);
  const [tool, setTool] = useState<ToolType>(ToolType.SpawnCountry);
  const [isRunning, setIsRunning] = useState(false);
  const [engine, setEngine] = useState<SimulationEngine>(() => createEngine(MapMode.World));

  // UI State
  const [tickCount, setTickCount] = useState(0);

  // Modals / Inspectors
  const [spawnLocation, setSpawnLocation] = useState<{x: number, y: number} | null>(null);
  const [selectedCountryId, setSelectedCountryId] = useState<number | null>(null);
  const [godModePaintingId, setGodModePaintingId] = useState<number | null>(null);

  // Refs for the loop
  const engineRef = useRef(engine);
  const animationFrameRef = useRef<number>();

  // Helper to re-generate map
  const handleGenerate = useCallback(() => {
    const newEngine = createEngine(mapMode);
    setEngine(newEngine);
    engineRef.current = newEngine;
    setTickCount(0);
    setIsRunning(false);
    setSelectedCountryId(null);
    setGodModePaintingId(null);
  }, [mapMode]);

  useEffect(() => {
    handleGenerate();
  }, [mapMode, handleGenerate]);

  // Simulation Loop
  useEffect(() => {
    if (!isRunning) return;
    const loop = () => {
      engineRef.current.tick();
      // Update react state if countries exist or events happened
      if (engineRef.current.countries.length > 0 || engineRef.current.events.length > 0) {
           setTickCount(prev => prev + 1);
      }
      animationFrameRef.current = requestAnimationFrame(loop);
    };
    animationFrameRef.current = requestAnimationFrame(loop);
    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [isRunning]);

  // Handle Canvas Interactivity
  const handleInteract = (x: number, y: number) => {
    const eng = engineRef.current;

    // Override if in God Mode Paint State
    if (godModePaintingId !== null && tool === ToolType.PaintTerritory) {
         eng.setCellOwner(x, y, godModePaintingId);
         return;
    }

    switch (tool) {
      case ToolType.Select: {
          const owner = eng.getOwnerAt(x, y);
          if (owner !== null) {
              setSelectedCountryId(owner);
              setGodModePaintingId(null); // Reset painting when selecting new
          } else {
              setSelectedCountryId(null);
          }
          break;
      }
      case ToolType.SpawnCountry:
        // Open Modal instead of spawning immediately
        setSpawnLocation({ x, y });
        break;
      case ToolType.PlaceCity:
        eng.placeCity(x, y);
        break;
      case ToolType.BrushLand:
        eng.paintTerrain(x, y, TerrainType.Land);
        break;
      case ToolType.BrushMountain:
        eng.paintTerrain(x, y, TerrainType.Mountain);
        break;
      case ToolType.BrushWater:
        eng.paintTerrain(x, y, TerrainType.Water);
        break;
      case ToolType.PaintTerritory:
         // Handled above in godMode check, but fallback here
         if (selectedCountryId) eng.setCellOwner(x, y, selectedCountryId);
         break;
    }
  };

  // Modal Callbacks
  const handleSpawnConfirm = (name: string, color: string) => {
      if (spawnLocation) {
          engineRef.current.spawnCountry(spawnLocation.x, spawnLocation.y, name, color);
          setTickCount(c => c + 1);
          setSpawnLocation(null);
      }
  };

  // God Mode Callbacks
  const handleDeleteCountry = (id: number) => {
      engineRef.current.deleteCountry(id);
      setSelectedCountryId(null);
      setTickCount(c => c + 1);
  };

  const handleUpdateCountry = (id: number, updates: Partial<Country>) => {
      engineRef.current.updateCountry(id, updates);
      setTickCount(c => c + 1);
  };

  const togglePaintTerritory = (id: number) => {
      if (godModePaintingId === id) {
          // Stop painting
          setGodModePaintingId(null);
          setTool(ToolType.Select);
      } else {
          // Start painting
          setGodModePaintingId(id);
          setTool(ToolType.PaintTerritory);
      }
  };

  return (
    <div className="w-screen h-screen bg-slate-950 flex flex-col relative">
      <Interface 
        mapMode={mapMode}
        setMapMode={setMapMode}
        tool={tool}
        setTool={(t) => {
             setTool(t);
             // If switching away from paint territory manually, stop painting
             if (t !== ToolType.PaintTerritory) setGodModePaintingId(null);
        }}
        isRunning={isRunning}
        toggleRun={() => setIsRunning(!isRunning)}
        onGenerate={handleGenerate}
      />

      <CanvasRenderer 
        engine={engine}
        onInteract={handleInteract}
        width={MAP_WIDTH}
        height={MAP_HEIGHT}
      />

      <EventLog events={engine.events} />
      <Leaderboard countries={engine.countries} />

      {spawnLocation && (
          <SpawnModal 
              x={spawnLocation.x} 
              y={spawnLocation.y} 
              onConfirm={handleSpawnConfirm} 
              onCancel={() => setSpawnLocation(null)}
          />
      )}

      {selectedCountryId && (
          <CountryInspector 
              country={engine.countries.find(c => c.id === selectedCountryId)!}
              onClose={() => setSelectedCountryId(null)}
              onDelete={handleDeleteCountry}
              onUpdate={handleUpdateCountry}
              onPaintTerritory={togglePaintTerritory}
              isPainting={godModePaintingId === selectedCountryId}
          />
      )}
    </div>
  );
}

import { Cell, Country, City, TerrainType, WorldEvent } from '../types';
import { MAP_WIDTH, MAP_HEIGHT } from './MapGenerators';
import { getRandomColor } from '../utils/random';

const CITY_NAMES_PREFIX = ['New', 'Old', 'Fort', 'Saint', 'Port', 'Mount', 'Lake', 'Grand', 'Little'];
const CITY_NAMES_SUFFIX = ['grad', 'town', 'ville', 'burg', 'ia', 'field', 'haven', 'side', 'wood'];

const generateCityName = () => {
  const p = CITY_NAMES_PREFIX[Math.floor(Math.random() * CITY_NAMES_PREFIX.length)];
  const s = CITY_NAMES_SUFFIX[Math.floor(Math.random() * CITY_NAMES_SUFFIX.length)];
  return `${p} ${s}`;
};

export class SimulationEngine {
  cells: Cell[];
  countries: Country[];
  cities: City[];
  events: WorldEvent[];
  width: number;
  height: number;
  tickCount: number = 0;

  // Game Logic state
  activeWars: Set<string> = new Set(); // Key "minId-maxId"

  constructor(cells: Cell[], width: number, height: number) {
    this.cells = cells;
    this.width = width;
    this.height = height;
    this.countries = [];
    this.cities = [];
    this.events = [];
  }

  // --- Helpers ---
  getIndex(x: number, y: number): number {
    if (x < 0 || x >= this.width || y < 0 || y >= this.height) return -1;
    return y * this.width + x;
  }

  getNeighbors(index: number): number[] {
    const x = index % this.width;
    const y = Math.floor(index / this.width);
    const neighbors = [];

    const dirs = [[0,1], [0,-1], [1,0], [-1,0]];
    for(const [dx, dy] of dirs) {
      const idx = this.getIndex(x + dx, y + dy);
      if (idx !== -1) neighbors.push(idx);
    }
    return neighbors;
  }

  // Get all cell indices within a radius (brush size)
  getIndicesInRadius(cx: number, cy: number, size: number): number[] {
    if (size <= 1) {
        const idx = this.getIndex(cx, cy);
        return idx !== -1 ? [idx] : [];
    }

    const indices: number[] = [];
    // Radius is roughly size-1
    const r = size - 1; 

    const minX = Math.max(0, cx - r);
    const maxX = Math.min(this.width - 1, cx + r);
    const minY = Math.max(0, cy - r);
    const maxY = Math.min(this.height - 1, cy + r);

    for (let y = minY; y <= maxY; y++) {
        for (let x = minX; x <= maxX; x++) {
             const dx = x - cx;
             const dy = y - cy;
             // Circle check with slight smoothing
             if (dx*dx + dy*dy <= r * r + 0.5) {
                 const idx = this.getIndex(x, y);
                 if (idx !== -1) indices.push(idx);
             }
        }
    }
    return indices;
  }

  logEvent(message: string, type: WorldEvent['type']) {
    this.events.unshift({
        id: Math.random(),
        message,
        type,
        timestamp: this.tickCount
    });
    if (this.events.length > 50) this.events.pop();
  }

  getWarKey(id1: number, id2: number) {
      return id1 < id2 ? `${id1}-${id2}` : `${id2}-${id1}`;
  }

  // --- Actions ---

  spawnCountry(x: number, y: number, name?: string, color?: string): void {
    const idx = this.getIndex(x, y);
    if (idx === -1) return;

    const cell = this.cells[idx];
    if (cell.terrain === TerrainType.Water) return;

    // Check if already owned
    if (cell.ownerId !== null) return;

    const newId = this.countries.length > 0 ? Math.max(...this.countries.map(c => c.id)) + 1 : 1;
    const finalColor = color || getRandomColor();
    const finalName = name || `Nation ${newId}`;

    const newCountry: Country = {
      id: newId,
      name: finalName,
      color: finalColor,
      score: 1,
      money: 0,
      capitalId: idx,
    };

    this.countries.push(newCountry);
    cell.ownerId = newId;
    cell.defense = 100; // Strong start

    this.placeCity(x, y, `${finalName} Capital`);
    this.logEvent(`${finalName} has been founded.`, 'spawn');
  }

  // God Mode: Set ownership directly (supports brush size)
  setCellOwner(x: number, y: number, countryId: number, size: number = 1): void {
    const indices = this.getIndicesInRadius(x, y, size);

    for (const idx of indices) {
        const cell = this.cells[idx];
        if (cell.terrain !== TerrainType.Water) {
            cell.ownerId = countryId;
            cell.defense = 100;
        }
    }
  }

  // God Mode: Delete Country
  deleteCountry(id: number): void {
      const country = this.countries.find(c => c.id === id);
      if (country) {
        this.logEvent(`${country.name} was removed by divine intervention.`, 'annex');
      }
      this.countries = this.countries.filter(c => c.id !== id);
      // Clear cells
      for (const cell of this.cells) {
          if (cell.ownerId === id) {
              cell.ownerId = null;
              cell.defense = 0;
          }
      }
      // Clear cities ownership
      for (const city of this.cities) {
          if (city.ownerId === id) city.ownerId = null;
      }
  }

  // God Mode: Rename/Recolor
  updateCountry(id: number, updates: Partial<Country>) {
      const country = this.countries.find(c => c.id === id);
      if (country) {
          Object.assign(country, updates);
      }
  }

  placeCity(x: number, y: number, name?: string): void {
     const idx = this.getIndex(x, y);
     if (idx === -1) return;
     const cell = this.cells[idx];
     if (cell.terrain === TerrainType.Water) return;

     // Prevent duplicates
     if (cell.cityId !== null) return;

     const cityId = this.cities.length + 1;
     this.cities.push({
         id: cityId,
         name: name || generateCityName(),
         cellIndex: idx,
         ownerId: cell.ownerId
     });
     cell.cityId = cityId;
     cell.defense += 50; // Bonus defense
  }

  paintTerrain(x: number, y: number, type: TerrainType, size: number = 1): void {
      const indices = this.getIndicesInRadius(x, y, size);

      for (const idx of indices) {
          this.cells[idx].terrain = type;
          // Reset ownership if turning to water
          if (type === TerrainType.Water) {
              this.cells[idx].ownerId = null;
              this.cells[idx].cityId = null;
              this.cells[idx].defense = 0;
          }
      }
  }

  getOwnerAt(x: number, y: number): number | null {
      const idx = this.getIndex(x, y);
      if (idx === -1) return null;
      return this.cells[idx].ownerId;
  }

  // --- Tick Logic ---

  tick(): void {
    this.tickCount++;
    const numUpdates = Math.floor(this.cells.length * 0.2); 

    for (let i = 0; i < numUpdates; i++) {
        const idx = Math.floor(Math.random() * this.cells.length);
        this.processCell(idx);
    }

    // Occasional Global Checks (Revolts, Alliances)
    if (Math.random() < 0.01) {
        this.checkRevolts();
    }

    this.updateScores();
  }

  processCell(idx: number) {
      const cell = this.cells[idx];

      // Only owned land acts
      if (cell.ownerId === null || cell.terrain === TerrainType.Water) return;

      const neighbors = this.getNeighbors(idx);
      const neighborIdx = neighbors[Math.floor(Math.random() * neighbors.length)];
      const target = this.cells[neighborIdx];

      // Interaction Logic
      if (target.terrain === TerrainType.Water) return;

      // 1. Expansion (Claim Empty Land)
      if (target.ownerId === null) {
          // Mountains are harder to claim
          const difficulty = target.terrain === TerrainType.Mountain ? 0.1 : 0.8;
          if (Math.random() < difficulty) {
              target.ownerId = cell.ownerId;
              target.defense = 10;
          }
          return;
      }

      // 2. War (Attack Enemy)
      if (target.ownerId !== cell.ownerId) {
          // Check War Start
          const warKey = this.getWarKey(cell.ownerId, target.ownerId);
          if (!this.activeWars.has(warKey)) {
              this.activeWars.add(warKey);
              const c1 = this.countries.find(c => c.id === cell.ownerId);
              const c2 = this.countries.find(c => c.id === target.ownerId);
              if (c1 && c2) {
                  this.logEvent(`War broke out between ${c1.name} and ${c2.name}!`, 'war');
              }
          }

          const attackRoll = Math.random() * (cell.defense + 50);
          const defenseRoll = Math.random() * (target.defense + (target.cityId ? 50 : 0) + (target.terrain === TerrainType.Mountain ? 30 : 0));

          if (attackRoll > defenseRoll) {
              // Successful invasion
              target.defense -= 20;
              if (target.defense <= 0) {
                  target.ownerId = cell.ownerId;
                  target.defense = 20; // Reset defense for new owner

                  // Capture City Bonus
                  if (target.cityId) {
                      cell.defense += 50; 
                      const city = this.cities.find(c => c.id === target.cityId);
                      if (city) {
                          city.ownerId = cell.ownerId;
                          // Optional: Log city capture?
                          // this.logEvent(`${city.name} was captured!`, 'war');
                      }
                  }
              }
          } else {
              // Failed attack, defender hardens
              target.defense = Math.min(target.defense + 5, 100);
          }
      } else {
          // 3. Reinforce (Heal own land)
          if (target.defense < 100) {
              target.defense += 1;
          }
      }
  }

  updateScores() {
      // Reset scores
      const scores = new Map<number, number>();
      for(const cell of this.cells) {
          if (cell.ownerId) {
              const current = scores.get(cell.ownerId) || 0;
              scores.set(cell.ownerId, current + 1);
          }
      }

      const survivingCountries: Country[] = [];
      for(const c of this.countries) {
          const newScore = scores.get(c.id) || 0;

          if (c.score > 0 && newScore === 0) {
              // Country died this tick
              this.logEvent(`${c.name} has been annexed and wiped off the map.`, 'annex');
          } else if (newScore > 0 || c.score === 0) {
               // Alive or just spawned (score 0 but in list? spawn usually gives 1 score immediately)
               c.score = newScore;
               survivingCountries.push(c);
          }
      }
      this.countries = survivingCountries;
  }

  checkRevolts() {
    if (this.countries.length === 0) return;
    const country = this.countries[Math.floor(Math.random() * this.countries.length)];
    if (country.score < 10) return; // Too small to revolt
    if (!country.capitalId) return;

    // BFS
    const queue = [country.capitalId];
    const visited = new Set<number>();
    visited.add(country.capitalId);

    let limit = 0;
    while(queue.length > 0 && limit < 5000) {
        limit++;
        const curr = queue.shift()!;
        const neighbors = this.getNeighbors(curr);
        for(const n of neighbors) {
            if (this.cells[n].ownerId === country.id && !visited.has(n)) {
                visited.add(n);
                queue.push(n);
            }
        }
    }

    // If visited count < total score, we have disconnected lands
    if (visited.size < country.score * 0.8) {
        const rebelId = this.countries.length > 0 ? Math.max(...this.countries.map(c => c.id)) + 1 : 1;
        const rebelColor = getRandomColor();
        const rebelName = `${country.name} Separatists`;

        const newRebel: Country = {
            id: rebelId,
            name: rebelName,
            color: rebelColor,
            score: 0,
            money: 0,
            isRebel: true,
            capitalId: null
        };
        this.countries.push(newRebel);

        // Convert unvisited cells to rebels
        let convertedCount = 0;
        for(let i=0; i<this.cells.length; i++) {
            if (this.cells[i].ownerId === country.id && !visited.has(i)) {
                this.cells[i].ownerId = rebelId;
                convertedCount++;
                if (this.countries[this.countries.length-1].capitalId === null) {
                    this.countries[this.countries.length-1].capitalId = i;
                    // Make new capital
                    this.placeCity(this.cells[i].x, this.cells[i].y, `${rebelName} HQ`);
                }
            }
        }

        if (convertedCount > 0) {
             this.logEvent(`Rebellion! ${rebelName} have risen up against ${country.name}.`, 'revolt');
        }
    }
  }
}

import React, { useState } from 'react';
import { MapMode, ToolType } from '../types';
